import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AnimatedLetters from '../AnimatedLetters';
import { fetchFootballNews } from '../../utils/footballNews';
import './index.scss';
import epLogo from '../../assets/images/EPLOGO.png';

const HOME_HEADLINE_COUNT = 5;

function formatHeadlineDate(iso) {
  if (!iso) return '';
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
  } catch {
    return '';
  }
}

const Home = () => {
  const [letterClass, setLetterClass] = useState('text-animate');
  const [headlines, setHeadlines] = useState([]);
  const [headlinesStatus, setHeadlinesStatus] = useState('loading');
  const nameArray = 'Welcome to'.split('');
  const jobArray = 'PremierZone'.split('');

  useEffect(() => {
    const timerId = setTimeout(() => {
      setLetterClass('text-animate-hover');
    }, 3000);
    return () => clearTimeout(timerId);
  }, []);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await fetchFootballNews();
        if (cancelled) return;
        setHeadlines((data.articles || []).slice(0, HOME_HEADLINE_COUNT));
        setHeadlinesStatus('ok');
      } catch {
        if (!cancelled) setHeadlinesStatus('error');
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <div className="home-page">
      <div className="overlay"></div>

      <div className="container hero-layout">
        <section className="hero-content">
          <p className="eyebrow">Premier League Intelligence Platform</p>
          <h1 className="hero-title">
            <img src={epLogo} alt="PremierZone logo" />
            <AnimatedLetters letterClass={letterClass} strArray={nameArray} idx={12} />
            <AnimatedLetters letterClass={letterClass} strArray={jobArray} idx={24} />
          </h1>
          <p className="hero-subtitle">
            A clean, professional hub for Premier League standings, match results, and club insights.
            Built for fast navigation and matchday clarity.
          </p>
          <div className="cta-row">
            <Link to="/standings" className="flat-button">View Standings</Link>
            <Link to="/results" className="secondary-button">Browse Results</Link>
          </div>
        </section>

        <aside className="hero-panel">
          <p className="panel-label">Quick Access</p>
          <div className="feature-list">
            <Link to="/standings" className="feature-card">
              <h3>Standings</h3>
              <p>Track the current table with season filters and qualification highlights.</p>
            </Link>
            <Link to="/results" className="feature-card">
              <h3>Results</h3>
              <p>Review fixtures by season and team with clear, logo-enhanced match cards.</p>
            </Link>
            <Link to="/teams" className="feature-card">
              <h3>Teams</h3>
              <p>Explore club-level views and player-focused data in one place.</p>
            </Link>
            <Link to="/news" className="feature-card">
              <h3>News</h3>
              <p>Premier League headlines from BBC Sport and The Guardian—same feed as the home page ticker.</p>
            </Link>
          </div>
        </aside>
      </div>

      <div className="container home-headlines-wrap">
        <section className="home-headlines" aria-labelledby="home-headlines-heading">
          <div className="home-headlines__top">
            <div>
              <p className="eyebrow">Live wires</p>
              <h2 id="home-headlines-heading" className="home-headlines__title">
                Premier League headlines
              </h2>
            </div>
            <Link to="/news" className="home-headlines__all">
              All EPL news
            </Link>
          </div>

          {headlinesStatus === 'loading' && (
            <p className="home-headlines__status">Loading latest headlines…</p>
          )}
          {headlinesStatus === 'error' && (
            <p className="home-headlines__status">
              Headlines need the API running. Open the{' '}
              <Link to="/news">News</Link> page or start the backend and refresh.
            </p>
          )}
          {headlinesStatus === 'ok' && headlines.length === 0 && (
            <p className="home-headlines__status">No stories right now. Try the full News page.</p>
          )}

          {headlines.length > 0 && (
            <ul className="home-headlines__list">
              {headlines.map((article) => (
                <li key={article.link || article.title}>
                  <a
                    className="home-headlines__link"
                    href={article.link}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <ArticleThumbnail imageUrl={article.imageUrl} variant="compact" />
                    <div className="home-headlines__text">
                      <span className="home-headlines__link-title">{article.title}</span>
                      <span className="home-headlines__link-meta">
                        {article.source}
                        {article.publishedAt ? ` · ${formatHeadlineDate(article.publishedAt)}` : ''}
                      </span>
                    </div>
                  </a>
                </li>
              ))}
            </ul>
          )}
        </section>
      </div>

      <div className="home-metrics container">
        <article className="metric-card">
          <p className="metric-value">20</p>
          <p className="metric-label">Premier League Clubs</p>
        </article>
        <article className="metric-card">
          <p className="metric-value">380</p>
          <p className="metric-label">Matches Per Season</p>
        </article>
        <article className="metric-card">
          <p className="metric-value">Latest</p>
          <p className="metric-label">Season-first tables and results</p>
        </article>
      </div>
    </div>
  );
};

export default Home;
